$processed = 0;
$skipped   = 0;
$errors    = 0;

while($record = $button->getNextSelectedRecord())
{
    $id_import   = $record["id"];
    $tanggal     = $record["tanggal"];
    $bpjs        = $record["bpjs"];
    $nik_import  = $record["nik"];
    $tahun_input = date('Y', strtotime($tanggal));

    // Ambil nik DAN gampong sekaligus dari pasien
    $sql_cari = "
        SELECT nik, id_gampong FROM pasien
        WHERE 
            ('" . addslashes($bpjs) . "' <> '' AND bpjs = '" . addslashes($bpjs) . "')
            OR
            ('" . addslashes($nik_import) . "' <> '' AND nik = '" . addslashes($nik_import) . "')
        LIMIT 1
    ";
    $rs     = DB::Query($sql_cari);
    $pasien = $rs->fetchAssoc();

    if (!$pasien) {
        $skipped++;
        continue;
    }

    $nik     = addslashes($pasien["nik"]);
    $gampong = addslashes($pasien["id_gampong"]);

    // Cek duplikat setahun
    $cek     = DB::Query("SELECT COUNT(*) AS total FROM daftar WHERE nik='$nik' AND tahun='$tahun_input'");
    $cekdata = $cek->fetchAssoc();

    if ($cekdata["total"] > 0) {
        $skipped++;
        continue;
    }

    // Generate ID unik 15 digit
    $uniqueKey = substr(str_replace('.', '', uniqid('', true)) . mt_rand(1000, 9999), 0, 15);

    // Cek ID tidak bentrok
    $cekId = DB::Query("SELECT COUNT(*) AS c FROM daftar WHERE id='$uniqueKey'");
    if ($cekId->fetchAssoc()["c"] > 0) {
        $uniqueKey = substr(str_replace('.', '', uniqid('', true)) . mt_rand(10000, 99999), 0, 15);
    }

    // Insert ke daftar — jumlah kolom dan values sekarang sesuai
    $hasil = DB::Exec("
        INSERT INTO daftar (id, nik, tanggal, status, tahun, gampong)
        VALUES ('$uniqueKey', '$nik', '" . addslashes($tanggal) . "', 'disetujui', '$tahun_input', '$gampong')
    ");

    if ($hasil) {
        DB::Exec("DELETE FROM import WHERE id='" . addslashes($id_import) . "'");
        $processed++;
    } else {
        $errors++;
    }
}








// Hapus echo lama, ganti dengan ini:
$pesan  = "Selesai!\\n";
$pesan .= "Diproses : " . $processed . "\\n";
$pesan .= "Dilewati : " . $skipped . "\\n";
$pesan .= "Gagal    : " . $errors;

echo "<script>
$(document).ready(function() {
    alert('" . $pesan . "');
});
</script>";
